tem.caseId))\n+  );\n+\n+  const shipmentDelayed = order.status === policy.appliesToStatus && order.fulfillment?.delayed;\n+  const highValue = order.valueCents >= policy.minValueCents;\n+  const strategicAccount = policy.requiredAccountTiers.includes(account.tier);\n+  const openSupportCase = supportCases.length > 0;\n+  const paymentRisk = Boolean(invoiceRisk);\n+  const usageDrop = usage?.trend === \"down\" || usage?.activeUsers7d < usage?.activeUsersPrevious7d;\n+  const regulatoryReview = Boolean(activeComplianceReview);\n+\n+  if (!shipmentDelayed || !highValue || !strategicAccount || !openSupportCase || !paymentRisk || !usageDrop || !regulatoryReview) {\n+    return buildPortalView(db, orderId);\n+  }\n+\n+  const escalationId = `esc-${orderId.toLowerCase()}`;\n+  const dueAt = order.fulfillment?.promisedReleaseTime || order.promisedReleaseTime;\n+  const usageDropPercent = usage?.activeUsersPrevious7d\n+    ? Math.round(((usage.activeUsersPrevious7d - usage.activeUsers7d) / usage.activeUsersPrevious7d) * 100)\n+    : 0;\n+  const timeline = [\n+    ...order.statusHistory.map((item) => ({\n+      type: \"order_status\",\n+      occurredAt: item.occurredAt,\n+      customerVisible: item.customerVisible,\n+      summary: item.summary\n+    })),\n+    ...activities.map((item) => ({\n+      type: \"customer_activity\",\n+      occurredAt: item.occurredAt,\n+      caseId: item.caseId,\n+      summary: item.summary\n+    })),\n+    {\n+      type: \"escalation_created\",\n+      occurredAt: now,\n+      customerVisible: true,\n+      summary: policy.customerVisibleTitle\n+    }\n+  ].sort((left, right) => left.occurredAt.localeCompare(right.occurredAt));\n+  const riskFactors = [\n+    {\n+      factor: \"shipment delay\",\n+      detail: `Shipment ${order.fulfillment.shipmentId} is delayed by ${order.fulfillment.carrier} because ${order.fulfillment.delayReason}.`,\n+      evidence: {\n+        shipmentId: order.fulfillment.shipmentId,\n+        status: order.status,\n+        promisedReleaseTime: order.fulfillment.promisedReleaseTime\n+      }\n+    },\n+    {\n+      factor: \"strategic account\",\n+      detail: `${account.name} is a ${account.tier} account on ${account.contract.tier} contract tier with ARR ${account.contract.arrCents}.`,\n+      evidence: {\n+        accountId: account._id,\n+        contractId: account.contract.contractId,\n+        renewalDate: account.contract.renewalDate\n+      }\n+    },\n+    {\n+      factor: \"open support case\",\n+      detail: `${supportCases.length} open support case(s), including ${supportCases.map((item) => item.caseId).join(\", \")}.`,\n+      evidence: {\n+        caseIds: supportCases.map((item) => item.caseId),\n+        latestComment: supportCases.at(-1)?.latestComment\n+      }\n+    },\n+    {\n+      factor: \"invoice risk\",\n+      detail: `Invoice ${invoiceRisk.invoiceId} is ${invoiceRisk.status} with risk ${invoiceRisk.risk}.`,\n+      evidence: {\n+        invoiceId: invoiceRisk.invoiceId,\n+        amountCents: invoiceRisk.amountCents,\n+        dueAt: invoiceRisk.dueAt\n+      }\n+    },\n+    {\n+      factor: \"usage drop\",\n+      detail: `7-day active users fell from ${usage.activeUsersPrevious7d} to ${usage.activeUsers7d} (${usageDropPercent}% drop).`,\n+      evidence: {\n+        snapshotId: usage.snapshotId,\n+        failedSyncs24h: usage.failedSyncs24h,\n+        trend: usage.trend\n+      }\n+    },\n+    {\n+      factor: \"regulatory review\",\n+      detail: `Compliance review ${activeComplianceReview.reviewId} is ${activeComplianceReview.status} for ${activeComplianceReview.flags.join(\", \")}.`,\n+      evidence: {\n+        reviewId: activeComplianceReview.reviewId,\n+        flags: activeComplianceReview.flags\n+      }\n+    }\n+  ];\n+  const ownerGroups = [...policy.ownerGroups];\n+  const tasks = ownerGroups.map((ownerGroup) => {\n+    const owner = account.accountTeam.find((item) => item.ownerGroup === ownerGroup);\n+\n+    return {\n+      _id: `work-${escalationId}-${ownerGroup.toLowerCase().replaceAll(\" \", \"-\")}`,\n+      escalationId,\n+      accountId: account._id,\n+      orderId,\n+      ownerGroup,\n+      ownerName: owner?.name,\n+      title: taskTitleFor(ownerGroup, account, order),\n+      status: \"open\",\n+      dueAt,\n+      dueContext: policy.nextStep,\n+      createdAt: now\n+    };\n+  });\n+  const auditEvents = [\n+    {\n+      _id: `audit-${escalationId}-risk-assessed`,\n+      escalationId,\n+      accountId: account._id,\n+      orderId,\n+      occurredAt: now,\n+      eventType: \"customer_360_risk_assessed\",\n+      actor: \"order-exception-workflow\",\n+      customerVisible: false,\n+      summary: \"Six customer 360 risk signals qualified the order for executive escalation.\",\n+      riskFactors: riskFactors.map((item) => item.factor),\n+      linkedDocuments: linkedDocuments(order, supportCases, invoiceRisks, usage, complianceReviews)\n+    },\n+    {\n+      _id: `audit-${escalationId}-tasks-created`,\n+      escalationId,\n+      accountId: account._id,\n+      orderId,\n+      occurredAt: now,\n+      eventType: \"owner_tasks_created\",\n+      actor: \"order-exception-workflow\",\n+      customerVisible: false,\n+      summary: \"Owner tasks routed to Customer Success, Legal, Finance, and Support.\",\n+      taskIds: tasks.map((item) => item._id)\n+    },\n+    {\n+      _id: `audit-${escalationId}-customer-visible`,\n+      escalationId,\n+      accountId: account._id,\n+      orderId,\n+      occurredAt: now,\n+      eventType: \"customer_portal_escalation_published\",\n+      actor: \"order-exception-workflow\",\n+      customerVisible: true,\n+      summary: policy.customerVisibleTitle,\n+      customerMessage: policy.customerMessage,\n+      timeline\n+    }\n+  ];\n+  const escalation = {\n+    _id: escalationId,\n+    escalationId,\n+    policyId: policy.policyId,\n+    accountId: account._id,\n+    orderId,\n+    status: \"active\",\n+    phase: \"executive_escalation\",\n+    customerVisibleTitle: policy.customerVisibleTitle,\n+    customerVisibleStatus: policy.customerVisibleStatus,\n+    ownerGroups,\n+    nextStep: policy.nextStep,\n+    customerMessage: policy.customerMessage,\n+    riskFactors,\n+    taskIds: tasks.map((item) => item._id),\n+    auditEventIds: auditEvents.map((item) => item._id),\n+    linkedDocuments: linkedDocuments(order, supportCases, invoiceRisks, usage, complianceReviews),\n+    timeline,\n+    createdAt: now,\n+    updatedAt: now\n+  };\n+\n+  upsertById(db.customer_escalations, escalation);\n+  tasks.forEach((task) => upsertById(db.work_items, task));\n+  auditEvents.forEach((event) => upsertById(db.audit_events, event));\n+\n+  account.currentEscalation = { ...escalation };\n+  account.taskSummary = tasks.map((item) => ({\n+    taskId: item._id,\n+    ownerGroup: item.ownerGroup,\n+    title: item.title,\n+    dueAt: item.dueAt,\n+    status: item.status\n+  }));\n+  order.exception = {\n+    escalationId,\n+    customerTitle: policy.customerVisibleTitle,\n+    customerStatus: policy.customerVisibleStatus,\n+    ownerGroups,\n+    nextStep: policy.nextStep,\n+    customerMessage: policy.customerMessage,\n+    auditEventIds: auditEvents.map((item) => item._id)\n+  };\n+\n   return buildPortalView(db, orderId);\n }\n+\n+function latestByDate(items, field) {\n+  return [...items].sort((left, right) => right[field].localeCompare(left[field]))[0];\n+}\n+\n+function upsertById(collection, document) {\n+  const index = collection.findIndex((item) => item._id === document._id);\n+  if (index === -1) {\n+    collection.push(document);\n+  } else {\n+    collection[index] = document;\n+  }\n+}\n+\n+function taskTitleFor(ownerGroup, account, order) {\n+  const titles = {\n+    \"Customer Success\": `Own executive recovery plan for ${account.name}`,\n+    Legal: `Review regulated shipment language for ${order._id}`,\n+    Finance: `Resolve invoice risk for ${account.name}`,\n+    Support: `Coordinate delayed shipment support for ${order._id}`\n+  };\n+\n+  return titles[ownerGroup];\n+}\n+\n+function linkedDocuments(order, supportCases, invoiceRisks, usage, complianceReviews) {\n+  return {\n+    orderId: order._id,\n+    shipmentId: order.fulfillment?.shipmentId,\n+    supportCaseIds: supportCases.map((item) => item.caseId),\n+    invoiceIds: invoiceRisks.map((item) => item.invoiceId),\n+    usageSnapshotId: usage?.snapshotId,\n+    complianceReviewIds: complianceReviews.map((item) => item.reviewId)\n+  };\n+}\n"
/Users/rom.iluz/Dev/sql-hidden-cost/prototypes/lab-console/evidence/order-exception-codex-v1/evidence-bundle.json:772:          "body": "diff --git a/src/order-exception-workflow.mjs b/src/order-exception-workflow.mjs\nindex b853cb0..b5b522e 100644\n--- a/src/order-exception-workflow.mjs\n+++ b/src/order-exception-workflow.mjs\n@@ -1,6 +1,226 @@\n import { buildPortalView } from \"./portal-view.mjs\";\n \n export function applyOrderException(tables, orderId, now) {\n-  // TODO: Implement the at-risk customer 360 escalation workflow.\n+  const order = required(tables.orders.find((item) => item.order_id === orderId), `Order not found: ${orderId}`);\n+  const account = required(\n+    tables.accounts.find((item) => item.account_id === order.account_id),\n+    `Account not found: ${order.account_id}`\n+  );\n+  const policy = tables.escalation_policies.find((item) =>\n+    item.applies_to_status === order.current_status &&\n+    order.value_cents >= item.min_value_cents &&\n+    account.tier_id === \"strategic\"\n+  );\n+\n+  if (!policy) return buildPortalView(tables, orderId);\n+\n+  const escalationId = `esc-${orderId.toLowerCase()}`;\n+  const shipment = tables.shipments.find((item) => item.order_id === orderId);\n+  const invoice = tables.invoices.find((item) => item.order_id === orderId);\n+  const payment = tables.payments.find((item) => item.order_id === orderId);\n+  const paymentRisk = invoice && tables.payment_risk_events.find((item) => item.invoice_id === invoice.invoice_id);\n+  const contract = tables.account_contracts.find((item) => item.account_id === account.account_id);\n+  const usage = latestBy(tables.usage_snapshots.filter((item) => item.account_id === account.account_id), \"captured_at\");\n+  const supportCases = tables.support_cases.filter((item) =>\n+    item.account_id === account.account_id &&\n+    item.status !== \"closed\" &&\n+    (item.order_id === orderId || item.order_id === null)\n+  );\n+  const complianceReview = tables.compliance_reviews.find((item) =>\n+    item.account_id === account.account_id &&\n+    item.order_id === orderId &&\n+    item.status !== \"cleared\"\n+  );\n+  const complianceFlags = complianceReview\n+    ? tables.compliance_review_flags\n+      .filter((item) => item.review_id === complianceReview.review_id)\n+      .map((item) => item.flag)\n+    : [];\n+  const shipmentFlags = shipment\n+    ? tables.shipment_regulatory_flags\n+      .filter((item) => item.shipment_id === shipment.shipment_id)\n+      .map((item) => item.flag)\n+    : [];\n+\n+  const escalation = upsert(tables.customer_escalations, \"escalation_id\", {\n+    escalation_id: escalationId,\n+    policy_id: policy.policy_id,\n+    account_id: account.account_id,\n+    order_id: order.order_id,\n+    status: \"active\",\n+    customer_visible_title: policy.customer_visible_title,\n+    customer_visible_status: policy.customer_visible_status,\n+    next_step: policy.next_step,\n+    customer_message: policy.customer_message,\n+    created_at: now,\n+    updated_at: now\n+  });\n+\n+  const riskFactors = [\n+    [\n+      \"shipment delay\",\n+      shipment\n+        ? `${shipment.carrier} reported ${shipment.delay_reason}; release target ${shipment.promised_release_time}.`\n+        : \"Order status is delayed and shipment details are unavailable.\"\n+    ],\n+    [\n+      \"strategic account\",\n+      `${account.name} is a ${account.tier_id} account on ${contract?.contract_tier ?? \"unknown\"} contract tier.`\n+    ],\n+    [\n+      \"open support case\",\n+      supportCases.map((item) => `${item.case_id} ${item.priority}: ${item.summary}`).join(\" | \")\n+    ],\n+    [\n+      \"invoice risk\",\n+      invoice\n+        ? `${invoice.invoice_id} is ${invoice.status}; risk ${invoice.risk ?? paymentRisk?.risk_code ?? \"none\"}; payment ${payment?.status ?? \"unknown\"}.`\n+        : \"No invoice found for the delayed order.\"\n+    ],\n+    [\n+      \"usage drop\",\n+      usage\n+        ? `${usage.active_users_7d} active users over 7d vs ${usage.active_users_previous_7d} prior; trend ${usage.trend}; ${usage.failed_syncs_24h} failed syncs in 24h.`\n+        : \"No recent usage snapshot found.\"\n+    ],\n+    [\n+      \"regulatory review\",\n+      complianceReview\n+        ? `${complianceReview.review_id} is ${complianceReview.status}; flags ${[...new Set([...shipmentFlags, ...complianceFlags])].join(\", \")}.`\n+        : \"No active regulatory review found.\"\n+    ]\n+  ];\n+\n+  riskFactors.forEach(([factor, detail], index) => {\n+    upsert(tables.escalation_risk_factors, \"risk_factor_id\", {\n+      risk_factor_id: `${escalationId}-risk-${index + 1}`,\n+      escalation_id: escalation.escalation_id,\n+      factor_order: index + 1,\n+      factor,\n+      detail,\n+      created_at: now\n+    });\n+  });\n+\n+  const dueAt = shipment?.promised_release_time ?? now;\n+  const taskTitles = {\n+    \"Customer Success\": \"Own executive recovery plan\",\n+    Legal: \"Review customer-safe escalation language\",\n+    Finance: \"Resolve invoice and payment risk\",\n+    Support: \"Coordinate support case updates\"\n+  };\n+\n+  tables.escalation_policy_steps\n+    .filter((item) => item.policy_id === policy.policy_id)\n+    .sort((a, b) => a.step_order - b.step_order)\n+    .forEach((step) => {\n+      const task = upsert(tables.escalation_tasks, \"task_id\", {\n+        task_id: `${escalationId}-task-${slug(step.owner_group)}`,\n+        escalation_id: escalation.escalation_id,\n+        account_id: account.account_id,\n+        order_id: order.order_id,\n+        owner_group: step.owner_group,\n+        title: taskTitles[step.owner_group] ?? `Review ${step.owner_group} escalation action`,\n+        status: \"open\",\n+        due_at: dueAt,\n+        created_at: now\n+      });\n+      const owner = tables.account_team_members.find((item) =>\n+        item.account_id === account.account_id &&\n+        item.owner_group === step.owner_group\n+      );\n+      if (owner) {\n+        upsert(tables.escalation_task_assignments, \"assignment_id\", {\n+          assignment_id: `${task.task_id}-assignment`,\n+          task_id: task.task_id,\n+          member_id: owner.member_id,\n+          assigned_at: now\n+        });\n+      }\n+    });\n+\n+  upsert(tables.customer_portal_messages, \"message_id\", {\n+    message_id: `${escalationId}-portal-message`,\n+    escalation_id: escalation.escalation_id,\n+    account_id: account.account_id,\n+    order_id: order.order_id,\n+    body: policy.customer_message,\n+    visibility: \"customer\",\n+    published_at: now\n+  });\n+\n+  upsert(tables.legal_review_requests, \"request_id\", {\n+    request_id: `${escalationId}-legal-review`,\n+    escalation_id: escalation.escalation_id,\n+    account_id: account.account_id,\n+    order_id: order.order_id,\n+    status: \"open\",\n+    reason: \"Customer-safe recovery language and regulatory review required.\",\n+    due_at: dueAt,\n+    created_at: now\n+  });\n+\n+  upsert(tables.finance_review_requests, \"request_id\", {\n+    request_id: `${escalationId}-finance-review`,\n+    escalation_id: escalation.escalation_id,\n+    account_id: account.account_id,\n+    order_id: order.order_id,\n+    status: \"open\",\n+    reason: \"Past-due invoice and payment hold risk require recovery alignment.\",\n+    due_at: dueAt,\n+    created_at: now\n+  });\n+\n+  const auditId = `${escalationId}-audit-activated`;\n+  upsert(tables.audit_events, \"audit_id\", {\n+    audit_id: auditId,\n+    subject_type: \"customer_escalation\",\n+    subject_id: escalation.escalation_id,\n+    event_type: \"customer_360_escalation_activated\",\n+    summary: \"Executive escalation activated with six risk factors, four owner tasks, and customer-safe portal status.\",\n+    customer_visible: true,\n+    occurred_at: now\n+  });\n+\n+  [\n+    [\"customer_escalation\", escalation.escalation_id],\n+    [\"order\", order.order_id],\n+    [\"account\", account.account_id],\n+    shipment && [\"shipment\", shipment.shipment_id],\n+    invoice && [\"invoice\", invoice.invoice_id],\n+    complianceReview && [\"compliance_review\", complianceReview.review_id],\n+    ...supportCases.map((item) => [\"support_case\", item.case_id])\n+  ].filter(Boolean).forEach(([subjectType, subjectId]) => {\n+    upsert(tables.audit_subjects, \"audit_subject_id\", {\n+      audit_subject_id: `${auditId}-${subjectType}-${subjectId}`,\n+      audit_id: auditId,\n+      subject_type: subjectType,\n+      subject_id: subjectId\n+    });\n+  });\n+\n   return buildPortalView(tables, orderId);\n }\n+\n+function required(value, message) {\n+  if (!value) throw new Error(message);\n+  return value;\n+}\n+\n+function latestBy(items, field) {\n+  return [...items].sort((a, b) => String(b[field]).localeCompare(String(a[field])))[0];\n+}\n+\n+function upsert(rows, key, row) {\n+  const existing = rows.find((item) => item[key] === row[key]);\n+  if (existing) {\n+    Object.assign(existing, row);\n+    return existing;\n+  }\n+  rows.push(row);\n+  return row;\n+}\n+\n+function slug(value) {\n+  return value.toLowerCase().replaceAll(\" \", \"-\");\n+}\n"
