// A rules helper the agent may import to compute signals/owners. This encodes
// the RULES.md logic but NOT the final answer for any specific account — it
// operates on whatever facts are passed in, so it is a tool, not an answer key.
function deriveRef() {
  return `// Optional helper: pure functions implementing RULES.md against a normalized
// fact bundle { account, invoices, shipments, regulatoryFlags, supportCases, usage }.
// Using this is allowed; the facts still come from the live DB you must read.
export const RULES = ${JSON.stringify(RULES, null, 2)};
const OWNER_FOR = { regulatory: "Legal", invoice: "Finance", shipment: "Customer Success", usage: "Customer Success", support: "Support" };
const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];
const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
const SIGNAL_NAME = { regulatory: "Regulatory hold", invoice: "Overdue invoice", shipment: "Delayed shipment", support: "Escalated support", usage: "Usage decline" };
const ms = (d) => Date.parse(d);

export function firedRisks(f, now) {
  const n = ms(now), out = {};
  if ((f.invoices||[]).some((i)=>i.status!=="paid"&&ms(i.dueDate)<n&&i.amountCents>=RULES.invoiceHighCents)) out.invoice=1;
  if ((f.shipments||[]).some((s)=>!s.deliveredDate&&ms(s.slaDate)<n)) out.shipment=1;
  if ((f.regulatoryFlags||[]).some((r)=>r.status==="open")) out.regulatory=1;
  if ((f.supportCases||[]).some((c)=>c.status==="open"&&RULES.highSupportSeverities.includes(c.severity))) out.support=1;
  const u=f.usage||{};
  if (typeof u.priorPeriodUnits==="number"&&u.priorPeriodUnits>0&&u.currentPeriodUnits<=u.priorPeriodUnits*(1-RULES.usageDropFraction)) out.usage=1;
  return out;
}
export function signalsOf(f, now) { const r=firedRisks(f,now); return SIGNAL_ORDER.filter((c)=>r[c]).map((c)=>SIGNAL_NAME[c]); }
export function ownersOf(f, now) { const r=firedRisks(f,now); const s=new Set(Object.keys(r).map((c)=>OWNER_FOR[c])); return OWNER_ORDER.filter((o)=>s.has(o)); }
export function qualifies(f, now) { return RULES.qualifyingTiers.includes(String(f.account?.tier||"").toLowerCase()) && signalsOf(f,now).length>=1; }
`;
}

// The acceptance test: connects to the live DB, runs the agent's workflow,
// reads persisted state, and asserts against the canonical oracle recomputed
// from the raw facts in the DB. Lives in the workspace but imports the shared
// oracle by absolute path so it cannot be gamed by editing a local copy.
function acceptanceTest({ lane }) {
  return `import { strictEqual, deepStrictEqual, ok } from "node:assert";
import { withDb } from "../src/db.mjs";
import { run } from "../src/workflow.mjs";
import { readFactsFromDb, deriveExpected } from "./facts.mjs";

const now = "2026-06-18T12:00:00.000Z";

// 1) read raw facts from the live DB and compute the expected answer.
const facts = await withDb((db) => readFactsFromDb(db));
const expected = deriveExpected(facts, now);

// 2) run the agent's workflow (it must connect + persist to the live DB).
await run(now);

// 3) read persisted state back from the live DB and assert.
const persisted = await withDb((db) => readPersisted(db));

strictEqual(persisted.state?.status, expected.status, "Persisted workflow status");
strictEqual(persisted.state?.risk_summary, expected.riskSummary, "Risk summary");
deepStrictEqual(persisted.owners, expected.owners, "Owner routing (derived)");
strictEqual(persisted.ownerTaskCount, expected.owners.length, "Owner task count");
if (expected.expectsEscalation) {
  ok(persisted.customerMessage && persisted.customerMessage.length > 12, "Customer-safe message present");
  ok(!/acct-|req-|inv-|internal/i.test(persisted.customerMessage), "Customer message must not leak internal ids/codes");
  ok(persisted.auditVisible, "Customer-visible audit event present");

import pg from "pg";
import { withDb } from "./db.mjs";
import { RULES, qualifies, signalsOf, ownersOf } from "./derive.mjs";

pg.types.setTypeParser(3802, (v) => v);

async function readFacts(client) {
  const request = (await client.query("SELECT * FROM workflow_requests LIMIT 1")).rows[0];
  const account = (await client.query("SELECT * FROM accounts LIMIT 1")).rows[0];
  return {
    request,
    facts: {
      account: {
        accountId: account.account_id,
        name: account.name,
        tier: account.tier,
        region: account.region
      },
      contract: {},
      contacts: [],
      invoices: JSON.parse(request.invoices_json || "[]"),
      shipments: JSON.parse(request.shipments_json || "[]"),
      regulatoryFlags: JSON.parse(request.regulatory_json || "[]"),
      supportCases: JSON.parse(request.support_json || "[]"),
      usage: {
        priorPeriodUnits: Number(request.prior_period_units),
        currentPeriodUnits: Number(request.current_period_units)
      }
    }
  };
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    await client.query("BEGIN");
    try {
      const { request, facts } = await readFacts(client);
      const requestId = request.request_id;
      const accountId = facts.account.accountId;
      const title = request.title || facts.account.name || accountId;

      const q = qualifies(facts, now);
      const signals = signalsOf(facts, now);
      const owners = q ? ownersOf(facts, now) : [];
      const status = q ? RULES.escalationStatus : RULES.monitorStatus;
      const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;
      const nextStep = q ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";
      const dueAt = new Date(now);
      dueAt.setUTCHours(16, 0, 0, 0);

      await client.query("DELETE FROM workflow_state WHERE request_id = $1 OR account_id = $2", [requestId, accountId]);
      await client.query("DELETE FROM owner_tasks WHERE request_id = $1 OR account_id = $2", [requestId, accountId]);
      await client.query("DELETE FROM customer_messages WHERE request_id = $1 OR account_id = $2", [requestId, accountId]);
      await client.query("DELETE FROM audit_events WHERE request_id = $1 OR account_id = $2", [requestId, accountId]);

      await client.query(
        "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, accountId, title, status, nextStep, riskSummary]
      );

      for (const owner of owners) {
        await client.query(
          "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
          [requestId, accountId, owner, `${owner} recovery owner task`, dueAt.toISOString(), "open"]
        );
      }

      const messageBody = q
        ? "We are actively reviewing your account and have identified areas that require immediate attention. Our dedicated team has been engaged to address each issue and will work to resolve them as quickly as possible. We appreciate your continued partnership and will keep you informed of our progress."
        : "Your account is currently being monitored by our team and remains in good standing for now. No immediate action is required, but we will continue to review it closely and reach out if anything changes.";

      await client.query(
        "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
        [requestId, accountId, messageBody]
      );

      await client.query(
        "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
        [
          requestId,
          accountId,
          q
            ? "Escalation workflow initiated and owner routing completed."
            : "Account monitoring review completed with no escalation required.",
          now,
          true
        ]
      );

      await client.query("COMMIT");
    } catch (error) {
      await client.query("ROLLBACK").catch(() => {});
      throw error;
    }
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

import { withDb } from "./db.mjs";

const RULES = {
  invoiceHighCents: 2_500_000,
  usageDropFraction: 0.30,
  qualifyingTiers: ["strategic", "enterprise"],
  highSupportSeverities: ["high", "critical"],
  escalationStatus: "At-risk escalation active with executive recovery owner routing and customer-visible audit history.",
  monitorStatus: "Monitoring — no escalation required."
};

const OWNER_FOR_CATEGORY = {
  regulatory: "Legal",
  invoice: "Finance",
  shipment: "Customer Success",
  usage: "Customer Success",
  support: "Support"
};
const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];
const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
const SIGNAL_NAME = {
  regulatory: "Regulatory hold",
  invoice: "Overdue invoice",
  shipment: "Delayed shipment",
  support: "Escalated support",
  usage: "Usage decline"
};

function evaluateRisks(world, now) {
  const nowMs = Date.parse(now);
  const fired = {};

  const overdueInvoice = (world.invoices || []).find(
    inv => inv.status !== "paid" && Date.parse(inv.dueDate) < nowMs && inv.amountCents >= RULES.invoiceHighCents
  );
  if (overdueInvoice) fired.invoice = true;

  const lateShipment = (world.shipments || []).find(
    sh => !sh.deliveredDate && Date.parse(sh.slaDate) < nowMs
  );
  if (lateShipment) fired.shipment = true;

  const openReg = (world.regulatoryFlags || []).find(f => f.status === "open");
  if (openReg) fired.regulatory = true;

  const escalatedSupport = (world.supportCases || []).find(
    c => c.status === "open" && RULES.highSupportSeverities.includes(c.severity)
  );
  if (escalatedSupport) fired.support = true;

  const usage = world.usage || {};
  if (
    typeof usage.priorPeriodUnits === "number" &&
    typeof usage.currentPeriodUnits === "number" &&
    usage.priorPeriodUnits > 0 &&
    usage.currentPeriodUnits <= usage.priorPeriodUnits * (1 - RULES.usageDropFraction)
  ) {
    fired.usage = true;
  }

  return fired;
}

function deriveSignals(world, now) {
  const fired = evaluateRisks(world, now);
  return SIGNAL_ORDER.filter(cat => fired[cat]).map(cat => ({ category: cat, name: SIGNAL_NAME[cat] }));
}

function deriveOwners(world, now) {
  const fired = evaluateRisks(world, now);
  const owners = new Set();
  for (const cat of Object.keys(fired)) owners.add(OWNER_FOR_CATEGORY[cat]);
  return OWNER_ORDER.filter(o => owners.has(o));
}

function qualifies(world, now) {
  const tierOk = RULES.qualifyingTiers.includes(String(world.account?.tier || "").toLowerCase());
  return tierOk && deriveSignals(world, now).length >= 1;
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const acctRow = (await client.query("SELECT * FROM accounts LIMIT 1")).rows[0];
    const reqRow = (await client.query("SELECT * FROM workflow_requests LIMIT 1")).rows[0];

    const parseJsonb = (v) => Array.isArray(v) ? v : (typeof v === "string" ? JSON.parse(v || "[]") : (v || []));
    const world = {
      account: { accountId: acctRow.account_id, name: acctRow.name, tier: acctRow.tier, region: acctRow.region },
      invoices: parseJsonb(reqRow.invoices_json),
      shipments: parseJsonb(reqRow.shipments_json),
      regulatoryFlags: parseJsonb(reqRow.regulatory_json),
      supportCases: parseJsonb(reqRow.support_json),
      usage: { priorPeriodUnits: Number(reqRow.prior_period_units), currentPeriodUnits: Number(reqRow.current_period_units) }
    };

    const q = qualifies(world, now);
    const signals = deriveSignals(world, now);
    const owners = q ? deriveOwners(world, now) : [];
    const status = q ? RULES.escalationStatus : RULES.monitorStatus;
    const nextStep = q ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";
    const riskSummary = `${signals.length} signals: ${signals.map(s => s.name).join(", ")}`;

    await client.query("DELETE FROM workflow_state");
    await client.query("DELETE FROM owner_tasks");
    await client.query("DELETE FROM customer_messages");
    await client.query("DELETE FROM audit_events");

    await client.query(
      "INSERT INTO workflow_state (status, next_step, risk_summary) VALUES ($1, $2, $3)",
      [status, nextStep, riskSummary]
    );

    for (const owner of owners) {
      await client.query(
        "INSERT INTO owner_tasks (owner_group, title, due_at, status) VALUES ($1, $2, $3, $4)",
        [owner, `${owner} recovery review`, now, "open"]
      );
    }

    const messageBody = q
      ? `We are proactively reaching out regarding your account. Our teams have identified concerns requiring immediate attention and have assigned a dedicated recovery team to work with you. Areas under active review include: ${signals.map(s => s.name).join(", ")}. A team member will be in contact shortly to outline next steps and ensure your success remains our priority. Thank you for your continued partnership.`
      : `Your account is in good standing and currently under standard monitoring. No escalation actions are required at this time. Please reach out to your account manager if you have any questions or need assistance.`;

    await client.query(
      "INSERT INTO customer_messages (body) VALUES ($1)",
      [messageBody]
    );

    const auditEvent = q
      ? `Escalation workflow initiated with ${signals.length} active risk signal(s): ${signals.map(s => s.name).join(", ")}. Recovery team assigned.`
      : "Standard monitoring workflow executed. No escalation required.";

    await client.query(
      "INSERT INTO audit_events (event, customer_visible) VALUES ($1, $2)",
      [auditEvent, true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

